/**
 * Return the greatest common divisor of the two arguments.
 * @param a first operand
 * @param b second operand
 * @return greatest common divisor of a and b
 */
public static int gcd(int a, int b) {
    // Euclid's method
    if (b == 0) {
        return (Math.abs(a));
    }
    a = Math.abs(a);
    b = Math.abs(b);
    while (b != 0) {
        int tmp = b;
        b = a % b;
        a = tmp;
    }
    return a;
}

