    int count = 2;
    while (itor.hasNext()) {
        int i = itor.next().intValue();
        if (i == avalue) {
            continue;
        }
        modulus = MathMDE.gcd(modulus, Math.abs(avalue - i));
        count++;
        if (modulus == 1) {
            return null;
